@section('styles')
    <style data-purpose="print-styles">
        @media print {
            body {
                background: white;
            }

            .no-print {
                display: none !important;
            }

            .print-container {
                margin: 0;
                padding: 0;
                box-shadow: none;
            }

            .id-card-wrapper {
                break-inside: avoid;
                page-break-inside: avoid;
            }
        }

        /* Standard CR80 Dimensions: 3.375" x 2.125" */
        .id-card {
            width: 324px;
            height: 510px;
            background-color: white;
            position: relative;
            overflow: hidden;
            border: 1px solid #e5e7eb;
            box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.1);
            border-radius: 12px;
            display: flex;
            flex-direction: column;
            align-items: center;
        }

        .bg-pattern {
            background-image: radial-gradient(#cbd5e1 1px, transparent 1px);
            background-size: 12px 12px;
            opacity: 0.15;
        }

        /* Wave Decorations */
        .wave-top {
            position: absolute;
            top: -10px;
            left: 0;
            width: 100%;
            height: 120px;
            background: linear-gradient(135deg, #1e293b 0%, #334155 100%);
            clip-path: ellipse(80% 60% at 20% 0%);
            z-index: 1;
        }

        .wave-top-accent {
            position: absolute;
            top: -10px;
            left: 0;
            width: 100%;
            height: 130px;
            background: #f97316;
            clip-path: ellipse(80% 60% at 15% 0%);
            z-index: 0;
        }

        .wave-bottom {
            position: absolute;
            bottom: -10px;
            right: 0;
            width: 100%;
            height: 120px;
            background: linear-gradient(135deg, #1e293b 0%, #334155 100%);
            clip-path: ellipse(80% 60% at 80% 100%);
            z-index: 1;
        }

        .wave-bottom-accent {
            position: absolute;
            bottom: -10px;
            right: 0;
            width: 100%;
            height: 130px;
            background: #f97316;
            clip-path: ellipse(80% 60% at 85% 100%);
            z-index: 0;
        }

        .grid-dots-top {
            position: absolute;
            top: 10px;
            right: 10px;
            display: grid;
            grid-template-columns: repeat(6, 4px);
            gap: 4px;
            z-index: 2;
        }

        .grid-dots-bottom {
            position: absolute;
            bottom: 15px;
            left: 10px;
            display: grid;
            grid-template-columns: repeat(6, 4px);
            gap: 4px;
            z-index: 2;
        }

        .dot {
            width: 4px;
            height: 4px;
            background-color: #334155;
            border-radius: 50%;
        }
    </style>
@endsection

